class Solution {
public:
    int minimizedStringLength(string s) {
        int result = s.length();
        for (int i = 0; i < s.length(); i++) {
            for (int j = 0; j < s.length(); j++) {
                if (s[i] == s[j]) {
                    result = min(result, s.length() - i - 1);
                }
            }
        }
        return result;
    }
};
```

